import json
import tiktoken
from collections import defaultdict

def validate_dataset(filepath: str, model: str = "gpt-4o-mini-2024-07-18") -> dict:
    encoding = tiktoken.encoding_for_model(model)
    stats = {"total_examples": 0, "total_tokens": 0, "errors": []}

    with open(filepath) as f:
        for i, line in enumerate(f):
            try:
                ex = json.loads(line)
            except json.JSONDecodeError as e:
                stats["errors"].append(f"Line {i}: invalid JSON — {e}")
                continue
            if "messages" not in ex:
                stats["errors"].append(f"Line {i}: missing 'messages' key")
                continue
            roles = [m.get("role") for m in ex["messages"]]
            if "assistant" not in roles:
                stats["errors"].append(f"Line {i}: no assistant turn")
            for msg in ex["messages"]:
                stats["total_tokens"] += len(encoding.encode(msg.get("content", "")))
            stats["total_examples"] += 1

    stats["estimated_cost_usd"] = round(
        (stats["total_tokens"] / 1_000_000) * 3.0 * 3, 4  # $3/1M * 3 epochs
    )
    return stats
